  baseball: Object.freeze({ path: 'baseball/mlb', label: 'MLB' }),
  basketball: Object.freeze({ path: 'basketball/nba', label: 'NBA' }),
  'ice-hockey': Object.freeze({ path: 'hockey/nhl', label: 'NHL' }),
});

const REQUIRED_COLUMNS = Object.freeze([
  'prediction_id',
  'event_id',
  'date',
  'sport',
  'league',
  'event',
  'market',
  'selection',
  'side',
  'odds_american',
  'odds_decimal',
  'implied_probability',
  'model_probability',
  'edge',
  'confidence_score',
  'status',
  'model_version',
  'stake',
