function settleRow(row, eventsBySport, flags) {
  const originalResult = normalizeResult(row.result || 'pending');
  const key = `${String(row.sport || '').toLowerCase()}:${row.date}`;
  const events = eventsBySport.get(key) ?? [];
  const event = findEvent(row, events);
  const next = { ...row };
  const messages = [];

  if (!event) {
    messages.push('No ESPN event match for settlement');
    return { row: next, event: null, previousResult: originalResult, changed: false, settlementStatus: 'unmatched', messages };
  }

  next.event_id = next.event_id || event.id;
  next.actual_home_score = event.home.score === null ? '' : String(event.home.score);
  next.actual_away_score = event.away.score === null ? '' : String(event.away.score);

  if (event.state !== 'post' || event.home.score === null || event.away.score === null) {
